mapper.select:
SELECT

FROM t_memory_context
WHERE session_id = #{sessionId}
  AND context_key = #{contextKey}

mapper.update:
UPDATE t_memory_context
SET context_value = #{contextValue},
    metadata = CAST(#{metadata} AS jsonb),
    updated_at = NOW()
WHERE session_id = #{sessionId}
  AND context_key = #{contextKey}

mapper.delete:
DELETE FROM t_memory_context
WHERE session_id = #{sessionId}
  AND context_key = #{contextKey}
